    @Override
    public String getMachineModeName(int mode) {
        return StatCollector.translateToLocal("MiracleDoor.modeMsg." + mode);
    }

    @Override
    public void getWailaBody(ItemStack itemStack, List<String> currentTip, IWailaDataAccessor accessor,
        IWailaConfigHandler config) {
        super.getWailaBody(itemStack, currentTip, accessor, config);
        final NBTTagCompound tag = accessor.getNBTData();
        if (tag.getBoolean("isActive")) {
            // #tr tst.miracleDoor.waila.currentOverclockParameter
            // # §bCurrent Overclock Parameter§r: §6%s
            // #zh_CN §b当前额外超频系数§r: §6%s
            currentTip.add(
                String.format(
                    StatCollector.translateToLocal("tst.miracleDoor.waila.currentOverclockParameter"),
                    tag.getLong("overclockParameter")));
        }
    }

    @Override
    public void getWailaNBTData(EntityPlayerMP player, TileEntity tile, NBTTagCompound tag, World world, int x, int y,
        int z) {
        super.getWailaNBTData(player, tile, tag, world, x, y, z);
        final IGregTechTileEntity tileEntity = getBaseMetaTileEntity();
        if (tileEntity != null) {
            tag.setInteger("overclockParameter", overclockParameter);
        }
    }

    @Override
    public void saveNBTData(NBTTagCompound aNBT) {
        super.saveNBTData(aNBT);
        aNBT.setByte("mode", (byte) machineMode);
        aNBT.setInteger("overclockParameter", overclockParameter);
        aNBT.setBoolean("isRendering", isRendering);
    }

    @Override
    public void loadNBTData(NBTTagCompound aNBT) {
        super.loadNBTData(aNBT);
        machineMode = aNBT.getByte("mode");
        overclockParameter = aNBT.getInteger("overclockParameter");
        isRendering = aNBT.getBoolean("isRendering");
    }

    @Override
    public RecipeMap<?> getRecipeMap() {
        if (machineMode == 1) return GTNCRecipeMaps.StellarForgeRecipes;
        return GTNCRecipeMaps.StellarForgeAlloySmelterRecipes;
    }

    @NotNull
    @Override
    public Collection<RecipeMap<?>> getAvailableRecipeMaps() {
        return Arrays.asList(GTNCRecipeMaps.StellarForgeRecipes, GTNCRecipeMaps.StellarForgeAlloySmelterRecipes);
    }

    @Override
    public boolean getDefaultWirelessMode() {
        return true;
    }

    @Override
    protected void prepareProcessing() {
        super.prepareProcessing();
        flushOverclockParameter();
    }

    @Override
    public int getExtraEUCostMultiplier() {
        return overclockParameter * (machineMode == 1 ? Config.MiracleDoor.multiplierOfEUCostEBFMode
            : Config.MiracleDoor.multiplierOfEUCostABSMode);
    }

    @Override
    public int getWirelessModeProcessingTime() {
        return Math.max(
            1,
            (machineMode == 1 ? Config.MiracleDoor.ticksOfProcessingTimeEBFMode
                : Config.MiracleDoor.ticksOfProcessingTimeABSMode) / this.overclockParameter);
    }

    @Nonnull
    @Override
    public CheckRecipeResult checkProcessing() {
        CheckRecipeResult r = super.checkProcessing();
        if (!r.wasSuccessful()) return r;
        if (!isRecipeProcessing) startRecipeProcessing();
        if (!consumePhoton(overclockParameter)) {
            // #tr GT5U.gui.text.shutdown_reason.no_critical_photon
            // # No Critical Photon input
            // # zh_CN 没有临界光子输入
            stopMachine(SimpleShutDownReason.ofCritical("no_critical_photon"));
            return CheckRecipeResultRegistry.NO_FUEL_FOUND;
        }
        // start the running star render at the geometric center
        if (!isRendering) {
            createRenderBlock();
            isRendering = true;
        }
        return CheckRecipeResultRegistry.SUCCESSFUL;
    }

    @Override
    public void onPostTick(IGregTechTileEntity aBaseMetaTileEntity, long aTick) {
        super.onPostTick(aBaseMetaTileEntity, aTick);
        // stop the render once the machine goes idle
        if (isRendering && mMaxProgresstime == 0) {
            destroyRenderBlock();
            isRendering = false;
        }
    }

    @Override
    public void onBlockDestroyed() {
        if (isRendering) {
            destroyRenderBlock();
            isRendering = false;
        }
        super.onBlockDestroyed();
    }

    /** Local offset (center block relative to controller) derived from the structure: 12 back + 32 up. */
    public void createRenderBlock() {
        int x = getBaseMetaTileEntity().getXCoord();
        int y = getBaseMetaTileEntity().getYCoord();
        int z = getBaseMetaTileEntity().getZCoord();

        double xOffset = 12 * getExtendedFacing().getRelativeBackInWorld().offsetX
            + 32 * getExtendedFacing().getRelativeUpInWorld().offsetX;
        double yOffset = 12 * getExtendedFacing().getRelativeBackInWorld().offsetY
            + 32 * getExtendedFacing().getRelativeUpInWorld().offsetY;
        double zOffset = 12 * getExtendedFacing().getRelativeBackInWorld().offsetZ
            + 32 * getExtendedFacing().getRelativeUpInWorld().offsetZ;

        this.getBaseMetaTileEntity()
            .getWorld()
            .setBlock((int) (x + xOffset), (int) (y + yOffset), (int) (z + zOffset), BlockLoader.blockMiracleStar);
    }

    public void destroyRenderBlock() {
        int x = getBaseMetaTileEntity().getXCoord();
        int y = getBaseMetaTileEntity().getYCoord();
        int z = getBaseMetaTileEntity().getZCoord();

        double xOffset = 12 * getExtendedFacing().getRelativeBackInWorld().offsetX
            + 32 * getExtendedFacing().getRelativeUpInWorld().offsetX;
        double yOffset = 12 * getExtendedFacing().getRelativeBackInWorld().offsetY
            + 32 * getExtendedFacing().getRelativeUpInWorld().offsetY;
        double zOffset = 12 * getExtendedFacing().getRelativeBackInWorld().offsetZ
            + 32 * getExtendedFacing().getRelativeUpInWorld().offsetZ;

        this.getBaseMetaTileEntity()
            .getWorld()
            .setBlock((int) (x + xOffset), (int) (y + yOffset), (int) (z + zOffset), Blocks.air);
    }

    private boolean consumePhoton(int amount) {
        int needAmount = amount;
        for (ItemStack items : getStoredInputsWithoutDualInputHatch()) {
            if (items == null) continue;
            if (GTUtility.areStacksEqual(items, GTNCItemList.MiracleDoorPhoton.get(1))) {
                if (items.stackSize >= needAmount) {
                    items.stackSize -= needAmount;
                    return true;
                } else {
                    needAmount -= items.stackSize;
                    items.stackSize = 0;
                }
            }
        }
        return false;
    }

    private void flushOverclockParameter() {
        ItemStack items = getControllerSlot();
        if (items != null && items.getItem() instanceof ItemIntegratedCircuit
            && items.getItemDamage() > 0
            && items.stackSize > 0) {
            this.overclockParameter = items.getItemDamage() * items.stackSize;
        } else {
            this.overclockParameter = 1;
        }
    }

    protected static GTRecipe turnToIngotRecipe(GTRecipe recipe) {
        GTRecipe r = recipe.copy();
        List<FluidStack> outputFluidList = new ArrayList<>();
        List<ItemStack> outputItemList = new ArrayList<>(Arrays.asList(r.mOutputs));
        for (FluidStack fluidStack : r.mFluidOutputs) {
            Fluid f = fluidStack.getFluid();
            ItemStack ingot = MoltenToIngot.get(f);
            if (ingot == null || fluidStack.amount < 144) {
                outputFluidList.add(fluidStack);
            } else {
                int ingotAmount = fluidStack.amount / 144;
                outputItemList.add(GTUtility.copyAmountUnsafe(ingotAmount, ingot));
                int remainingFluidAmount = fluidStack.amount - 144 * ingotAmount;
                if (remainingFluidAmount > 0) {
                    ScienceNotCool.LOG
                        .info("Miracle Door : Terrible molten fluid amount in recipe output being " + f.getName());
                    outputFluidList.add(new FluidStack(f, remainingFluidAmount));
                }
            }
        }
        r.mOutputs = outputItemList.toArray(new ItemStack[0]);
        r.mFluidOutputs = outputFluidList.toArray(new FluidStack[0]);
        return r;
    }

    @Override
    protected ProcessingLogic createProcessingLogic() {

        return new ProcessingLogic() {

            @Nonnull
            @Override
            protected OverclockCalculator createOverclockCalculator(@Nonnull GTRecipe recipe) {
                return OverclockCalculator.ofNoOverclock(recipe);
            }

            @Nonnull
            @Override
            protected Stream<GTRecipe> findRecipeMatches(@Nullable RecipeMap<?> map) {
                if (map == null) return Stream.empty();
                this.lastRecipe = null;

                // Get the right recipe
                Stream<GTRecipe> base = super.findRecipeMatches(map);

                // Only this recipe will be transformed
                boolean hasMold = false;
                if (this.inputItems != null) {
                    for (ItemStack s : this.inputItems) {
                        if (s != null && s.isItemEqual(IngotMold)) {
                            hasMold = true;
                            break;
                        }
                    }
                }

                if (hasMold) {
                    return base.map(GTNCMiracleDoor::turnToIngotRecipe);
                } else {
                    return base;
                }
            }

        }.setMaxParallel(Integer.MAX_VALUE);
    }

    @Override
    protected void setProcessingLogicPower(ProcessingLogic logic) {
        // The voltage is only used for recipe finding
        logic.setAvailableVoltage(Long.MAX_VALUE);
        logic.setAvailableAmperage(1);
        logic.setAmperageOC(false);
    }

    @Override
    public boolean onRunningTick(ItemStack aStack) {
        return true;
    }

    public int getMaxParallelRecipes() {
        return Integer.MAX_VALUE;
    }

    @Override
    public void checkMachine(IGregTechTileEntity aBaseMetaTileEntity, ItemStack aStack, List<StructureError> errors) {
        repairMachine();
        // Two alternative shapes: the main structure OR the "err" fallback structure.
        // Try the main piece into the real errors list; if it fails, retry the err piece,
        // reporting errors only when both variants fail.
        if (checkPiece(STRUCTURE_PIECE_MAIN, horizontalOffSet, verticalOffSet, depthOffSet, null)) {
            return;
        }
        checkPiece(STRUCTURE_PIECE_MAIN_ERR, horizontalOffSet, verticalOffSet, depthOffSet, errors);
    }
    // endregion

    // region Structure
    protected static final String STRUCTURE_PIECE_MAIN = "mainMiracleDoor";
    protected static final String STRUCTURE_PIECE_MAIN_ERR = "mainMiracleDoorErr";
    protected final int horizontalOffSet = 20;
    protected final int verticalOffSet = 52;
    protected final int depthOffSet = 8;
    protected static IStructureDefinition<GTNCMiracleDoor> STRUCTURE_DEFINITION = null;

    @Override
    public void construct(ItemStack stackSize, boolean hintsOnly) {
        repairMachine();
        buildPiece(STRUCTURE_PIECE_MAIN, stackSize, hintsOnly, horizontalOffSet, verticalOffSet, depthOffSet);
    }

    @Override
    public int survivalConstruct(ItemStack stackSize, int elementBudget, ISurvivalBuildEnvironment env) {
        if (this.mMachine) return -1;
        int realBudget = elementBudget >= 200 ? elementBudget : Math.min(200, elementBudget * 5);
        return this.survivalBuildPiece(
            STRUCTURE_PIECE_MAIN,
            stackSize,
            horizontalOffSet,
            verticalOffSet,
            depthOffSet,
            realBudget,
            env,
            false,
            true);
    }

    @Override
    public IStructureDefinition<GTNCMiracleDoor> getStructureDefinition() {
        if (STRUCTURE_DEFINITION == null) {
            STRUCTURE_DEFINITION = IStructureDefinition.<GTNCMiracleDoor>builder()
                .addShape(STRUCTURE_PIECE_MAIN, transpose(shapeMain))
                .addShape(STRUCTURE_PIECE_MAIN_ERR, transpose(shapeMainErr))
                .addElement('A', ofBlock(sBlockCasings2, 0))
                .addElement('B', ofBlock(GregTechAPI.sBlockStones, 3))
                .addElement('C', ofBlock(GregTechAPI.sBlockStones, 3))
                .addElement('D', ofBlock(sBlockCasings2, 0))
                .addElement('E', ofBlock(componentAssemblylineCasing, 0))
                .addElement('F', ofBlock(sBlockCasings2, 13))
                .addElement('G', ofBlock(sBlockCasings5, 0))
                .addElement('H', ofBlock(sBlockCasings1, 11))
                .addElement('I', ofBlock(sBlockCasings2, 0))
                .addElement('J', ofBlock(sBlockCasings4, 15))
                .addElement(
                    'L',
                    HatchElementBuilder.<GTNCMiracleDoor>builder()
                        .atLeast(InputBus, OutputBus, InputHatch, OutputHatch)
                        .adder(GTNCMiracleDoor::addToMachineList)
                        .hint(1)
                        .casingIndex(DENSEBRICKS)
                        .buildAndChain(sBlockCasings4, 15))
                .build();
        }
        return STRUCTURE_DEFINITION;
    }

